import{_ as c,r as o,o as u,c as p,a as e,b as a,t as i,d as t,w as n,n as _,g as f,e as m}from"./app-d223f2a5.js";const B={},b={id:"frontmatter-title-관련",tabindex:"-1"},k=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),x={class:"table-of-contents"},g=e("hr",null,null,-1),S=m('<hr><p>이 책에서 구현할 SBB의 기능은 아쉽지만 여기까지이다. 함께 더 많은 기능을 추가하고 싶지만 이 책은 SBB의 완성이 아니라 SBB를 성장시키며 얻게 되는 경험을 전달하는 것을 목표로 하고 있다.</p><p>이 책에서는 다루지 못했지만 구현하면 좋을것 같은 기능들이 몇 가지 있는데 여기에 간단하게 소개해 보았다. 아래에 소개한 기능들을 여러분 스스로 하나씩 구현해 가다보면 스프링부트에 대해서 더 깊게 이해할수 있게 될 것이다.</p><hr><h2 id="답변-페이징과-정렬" tabindex="-1"><a class="header-anchor" href="#답변-페이징과-정렬" aria-hidden="true">#</a> 답변 페이징과 정렬</h2><p>현재 하나의 질문에 무수히 많은 답변이 달릴 수 있는 구조이다. 만약 답변이 100개가 된다고 상상해 보자. 성능을 위해서라도 답변의 페이징은 반드시 필요할 것이다. 그리고 답변을 보여줄 때에도 최신순, 추천순 등으로 정렬하여 보여줄 수 있는 기능도 필요할 것이다. 유명한 질문 답변 사이트인 스택오버플로우(stackoverflow.com)나 레딧(reddit.com)을 보아도 항상 추천수가 많은 답변을 먼저 보여주고 있다.</p><p>여러분은 이미 질문 목록에 페이징과 정렬을 적용한 경험이 있기 때문에 답변에 페이징과 정렬을 적용하는 것이 그리 어렵지는 않을 것이다.</p><hr><h2 id="댓글" tabindex="-1"><a class="header-anchor" href="#댓글" aria-hidden="true">#</a> 댓글</h2><p>질문 또는 답변에 댓글을 달 수 있는 기능을 구현해 보자. Comment 라는 엔티티를 생성하고 Question, Answer 엔티티와 연결하면 쉽게 구현할 수 있을 것이다.</p><hr><h2 id="카테고리" tabindex="-1"><a class="header-anchor" href="#카테고리" aria-hidden="true">#</a> 카테고리</h2><p>현재는 &#39;질문답변&#39; 이라는 하나의 카테고리로만 게시판이 구성되지만 여기에 &#39;강좌&#39;나 &#39;자유게시판&#39;과 같은 게시판을 추가로 더 만들고 싶을 수도 있을 것이다. 이런 경우에 Question 엔티티에 Category 엔티티를 추가하여 게시판을 분류할 수 있을 것이다.</p><hr><h2 id="비밀번호-찾기와-변경" tabindex="-1"><a class="header-anchor" href="#비밀번호-찾기와-변경" aria-hidden="true">#</a> 비밀번호 찾기와 변경</h2><p>현재 사용자가 비밀번호를 분실했을때 조치할수 있는 방법이 없다. 비밀번호 분실 시 임시비밀번호를 가입할 때 등록한 이메일 주소로 발송하여 로그인 할 수 있도록 조치하는 간단한 방법을 구현해 보자. 그리고 비밀번호 변경 프로그램도 필요하다. 로그인 후 기존 비밀번호와 새 비밀번호를 입력받아 비밀번호를 변경할 수 있는 프로그램을 만들어 보자.</p><hr><h2 id="프로필" tabindex="-1"><a class="header-anchor" href="#프로필" aria-hidden="true">#</a> 프로필</h2><p>로그인 한 사용자의 프로필 화면을 만들어 보자. 이 화면에는 사용자에 대한 기본정보와 작성한 질문, 답변, 댓글 등을 확인할 수 있도록 하면 좋을 것이다.</p><hr><h2 id="최근-답변과-최근-댓글" tabindex="-1"><a class="header-anchor" href="#최근-답변과-최근-댓글" aria-hidden="true">#</a> 최근 답변과 최근 댓글</h2><p>현재 SBB는 질문글 위주로 목록이 보여진다. 하지만 최근에 작성된 답변이나 최근에 작성된 댓글이 궁금할 수도 있을 것이다. 최근 답변과 최근 댓글을 확인할 수 있는 기능을 추가해 보자.</p><hr><h2 id="조회-수" tabindex="-1"><a class="header-anchor" href="#조회-수" aria-hidden="true">#</a> 조회 수</h2><p>현재 SBB는 답변 수를 표시하고 있지만 조회 수는 표시하지 않는다. 조회 수를 표시해 보자.</p><hr><h2 id="소셜-로그인" tabindex="-1"><a class="header-anchor" href="#소셜-로그인" aria-hidden="true">#</a> 소셜 로그인</h2><p>SBB에 구글이나 페이스북, 트위터 등을 경유하여 로그인하는 소셜 로그인 기능을 구현해 보자.</p><hr><h2 id="마크다운-에디터" tabindex="-1"><a class="header-anchor" href="#마크다운-에디터" aria-hidden="true">#</a> 마크다운 에디터</h2>',30),v={href:"https://simplemde.com",target:"_blank",rel:"noopener noreferrer"},w=e("hr",null,null,-1);function C(l,V){const r=o("router-link"),h=o("VPCard"),d=o("ExternalLinkIcon"),s=o("TagLinks");return u(),p("div",null,[e("h1",b,[k,a(" "+i(l.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,i(l.$frontmatter.description),1)]),e("nav",x,[e("ul",null,[e("li",null,[t(r,{to:"#답변-페이징과-정렬"},{default:n(()=>[a("답변 페이징과 정렬")]),_:1})]),e("li",null,[t(r,{to:"#댓글"},{default:n(()=>[a("댓글")]),_:1})]),e("li",null,[t(r,{to:"#카테고리"},{default:n(()=>[a("카테고리")]),_:1})]),e("li",null,[t(r,{to:"#비밀번호-찾기와-변경"},{default:n(()=>[a("비밀번호 찾기와 변경")]),_:1})]),e("li",null,[t(r,{to:"#프로필"},{default:n(()=>[a("프로필")]),_:1})]),e("li",null,[t(r,{to:"#최근-답변과-최근-댓글"},{default:n(()=>[a("최근 답변과 최근 댓글")]),_:1})]),e("li",null,[t(r,{to:"#조회-수"},{default:n(()=>[a("조회 수")]),_:1})]),e("li",null,[t(r,{to:"#소셜-로그인"},{default:n(()=>[a("소셜 로그인")]),_:1})]),e("li",null,[t(r,{to:"#마크다운-에디터"},{default:n(()=>[a("마크다운 에디터")]),_:1})])])]),g,t(h,_(f({title:"3-15. SBB 추가 기능",desc:"점프 투 스프링부트 - WikiDocs",link:"https://wikidocs.net/162833",logo:"https://wikidocs.net/static/img/favicon.ico",color:"rgba(255, 255, 255, 0.2)"})),null,16),S,e("p",null,[a("마크다운 문법을 더 쉽게 입력할 수 있는 마크다운 에디터를 적용해 보자. 인터넷을 찾아보면 추천하는 마크다운 에디터가 몇 가지 있는데, 필자는 그중에서 "),e("a",v,[a("simpleMDE"),t(d)]),a("를 추천한다. simpleMDE를 SBB에 적용해 보자.")]),w,t(s)])}const D=c(B,[["render",C],["__file","03O.html.vue"]]);export{D as default};
